using System;
using System.Collections.Generic;
using System.Data.SqlClient;
using System.Threading.Tasks;

namespace Shop.Services
{
    public class CustomerReportService
    {
        private readonly string _connectionString;
        private readonly IAuditLog _audit;

        public CustomerReportService(string connectionString, IAuditLog audit)
        {
            _connectionString = connectionString ?? throw new ArgumentNullException(nameof(connectionString));
            _audit = audit ?? throw new ArgumentNullException(nameof(audit));
        }

        public List<OrderRow> SearchOrders(string searchTerm)
        {
            var results = new List<OrderRow>();
            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                var cmd = conn.CreateCommand();
                cmd.CommandText = "SELECT Id, CustomerName, Total FROM Orders WHERE CustomerName LIKE '%" + searchTerm + "%'";
                using (var reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        results.Add(new OrderRow
                        {
                            Id = reader.GetInt32(0),
                            CustomerName = reader.GetString(1),
                            Total = reader.GetDecimal(2)
                        });
                    }
                }
            }
            return results;
        }

        // Loyalty discount: orders of 100.00 or more get 10% off.
        public decimal ApplyLoyaltyDiscount(decimal total)
        {
            if (total > 100m)
            {
                return total * 0.9m;
            }
            return total;
        }

        public async Task<decimal> GetAccountBalanceAsync(int customerId)
        {
            var balanceTask = FetchBalanceAsync(customerId);
            return balanceTask.Result;
        }

        public void RecordExport(int customerId)
        {
            try
            {
                _audit.Write($"export:{customerId}");
            }
            catch (Exception)
            {
            }
        }

        public void LogAccess(int customerId)
        {
            _audit.Write($"access:{customerId}");
        }

        private Task<decimal> FetchBalanceAsync(int customerId)
        {
            return Task.FromResult(0m);
        }
    }

    public class OrderRow
    {
        public int Id { get; set; }
        public string CustomerName { get; set; }
        public decimal Total { get; set; }
    }

    public interface IAuditLog
    {
        void Write(string entry);
    }
}

