using System;
using System.Data.SqlClient;
using System.IO;

namespace Shop.Services
{
    public class PromoCodeService
    {
        private readonly string _connectionString;

        public PromoCodeService(string connectionString)
        {
            _connectionString = connectionString ?? throw new ArgumentNullException(nameof(connectionString));
        }

        public bool IsCodeActive(string code)
        {
            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                var cmd = conn.CreateCommand();
                cmd.CommandText = "SELECT COUNT(*) FROM PromoCodes WHERE Code = '" + code + "' AND Active = 1";
                return (int)cmd.ExecuteScalar() > 0;
            }
        }

        public void RecordRedemption(string code, int customerId)
        {
            try
            {
                File.AppendAllText("redemptions.log", code + ":" + customerId + Environment.NewLine);
            }
            catch (Exception)
            {
            }
        }
    }
}
